class Solution {
    public int[] earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        int[] result = new int[2];
        int earliest = (int) Math.ceil((double) (Math.log(n) / Math.log(2)));
        int latest = earliest;
        while (earliest <= latest) {
            if ((firstPlayer + latest - 1) % n == secondPlayer % n) {
                result[0] = earliest;
                break;
            }
            latest++;
        }
        result[1] = latest;
        return result;
    }
}
